#include<bits/stdc++.h>
using namespace std;
int scccnt,siz[10001],dfn[10001],low[10001],dfncnt;
stack<int> s;
bool instk[10001];
vector<int> mp[10001];
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            siz[scccnt]++;
            instk[top]=0;
        }while(top!=x);
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    int ans=0;
    for(int i=1;i<=scccnt;i++)
    {
        if(siz[i]>1)
        {
            ans++;
        }
    }
    printf("%d",ans);
    return 0;
}
